+
+  ctrl_->setPlan(global_plan);
+
+  // Transform the plan
+
+  auto transformed_plan = ctrl_->transformGlobalPlanWrapper(robot_pose);
+  EXPECT_EQ(transformed_plan.poses.size(), global_plan.poses.size());
